class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        if not self.intervals or self.intervals[-1][1] + 1 < value:
            self.intervals.append([value, value])
        else:
            if value == self.intervals[-1][1] + 1:
                self.intervals[-1][1] = value
            else:
                self.intervals.append([value, value])

    def getIntervals(self) -> List[List[int]]:
        self.intervals = [[interval[0], interval[1]] for interval in self.intervals if interval[0] == interval[1]]
        self.intervals = [[interval[0], interval[1]] for interval in self.intervals if interval[1] - interval[0] > 0]
        self.intervals.sort(key=lambda x: x[0])
        return self.intervals
